import React from "react";
import "./GithubStats.css";
import { greeting } from "../../portfolio";
import { Fade } from "react-reveal";

export default function GithubStats(props) {
  const theme = props.theme;
  const username = "soumadipchangder";
  return (
    <div className="github-stats-main" id="github-stats">
      <Fade bottom duration={1000} distance="20px">
        <h1 className="section-title-ai gradient-text">GitHub Activity</h1>
        <p className="section-subtitle-ai">My open source contributions and coding activity</p>
      </Fade>
      <Fade bottom duration={1500} distance="30px">
        <div className="github-stats-cards">
          <div className="github-stat-card glass-card">
            <img
              src={`https://github-readme-stats.vercel.app/api?username=${username}&show_icons=true&theme=transparent&hide_border=true&title_color=00d4ff&icon_color=7c3aed&text_color=8892a8&bg_color=00000000`}
              alt="GitHub Stats"
              className="github-stat-img"
            />
          </div>
          <div className="github-stat-card glass-card">
            <img
              src={`https://github-readme-stats.vercel.app/api/top-langs/?username=${username}&layout=compact&theme=transparent&hide_border=true&title_color=00d4ff&text_color=8892a8&bg_color=00000000`}
              alt="Top Languages"
              className="github-stat-img"
            />
          </div>
        </div>
        <div className="github-streak-container">
          <div className="github-stat-card glass-card">
            <img
              src={`https://github-readme-streak-stats.herokuapp.com/?user=${username}&theme=transparent&hide_border=true&ring=00d4ff&fire=7c3aed&currStreakLabel=00d4ff&sideLabels=8892a8&dates=8892a8&currStreakNum=e0e6f0&sideNums=e0e6f0&background=00000000`}
              alt="GitHub Streak"
              className="github-stat-img"
            />
          </div>
        </div>
      </Fade>
    </div>
  );
}
